#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=1e6+5;
int n,ans,a[maxn];
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n;
	for(int i=1,x,y; i<=n; i++) {
		cin>>x>>y;
		a[x]++;
		a[y+1]--;
	}
	for(int i=1;i<maxn;i++){
		a[i]+=a[i-1];
	}
	for(int i=0;i<maxn;i++){
		ans=max(ans,a[i]);
	}
	cout<<ans;
	return 0;
}
